const crypto = require('crypto');

// Calc app may post the payload at .body (webhook framing) or at root.
const raw = $input.first().json.body || $input.first().json;
const contact = raw.contact || {};

// Generate or preserve reportId for the customer-facing URL.
const chars = 'abcdefghijklmnopqrstuvwxyz0123456789';
let reportId = raw.report_id || raw.reportId || '';
if (!reportId) {
  for (let i = 0; i < 8; i++) reportId += chars[Math.floor(Math.random() * chars.length)];
}
const reportUrl = `https://iheartwoodcraft.com/report/${reportId}`;

// Coerce legacy contact_* keys into nested contact{} per LeadInput schema.
const payloadContact = {
  name:  contact.name  || raw.contact_name  || '',
  email: contact.email || raw.contact_email || '',
};
const phone = contact.phone || raw.contact_phone;
if (phone) payloadContact.phone = phone;
const notes = contact.notes || raw.contact_notes;
if (notes) payloadContact.notes = notes;

// Build the canonical LeadInput hwc-leads expects.
const leadPayload = {
  source: 'calculator',
  contact: payloadContact,
  calculator: raw.calculator || raw.calc_label || 'bathroom',
  projectState: raw.projectState || raw.project_state || {},
  reportId,
};
if (raw.estimate && typeof raw.estimate === 'object') {
  leadPayload.estimate = { low: raw.estimate.low, high: raw.estimate.high };
}

// Attribution — fold UTMs/GCLID/referrer into the schema's shape.
const attribution = {};
if (raw.utm_source)    attribution.utmSource   = raw.utm_source;
if (raw.utm_medium)    attribution.utmMedium   = raw.utm_medium;
if (raw.utm_campaign)  attribution.utmCampaign = raw.utm_campaign;
if (raw.gclid)         attribution.gclid       = raw.gclid;
if (raw.referrer)      attribution.referrer    = raw.referrer;
if (raw.landing_page)  attribution.landingPage = raw.landing_page;
if (typeof raw.pages_viewed === 'number') attribution.pagesViewed = raw.pages_viewed;
if (Object.keys(attribution).length > 0) leadPayload.attribution = attribution;

// Serialise once — HMAC signs these exact bytes; HTTP sends them.
const bodyJson = JSON.stringify(leadPayload);

const secret = $env.HWC_LEADS_HMAC_SECRET;
if (!secret) throw new Error('HWC_LEADS_HMAC_SECRET missing in env');
const sig = crypto.createHmac('sha256', secret).update(bodyJson).digest('hex');

return [{
  json: {
    bodyJson,
    sig,
    reportId,
    reportUrl,
  }
}];
